_fireChainZap(baseAngle, stacks) {
  const target = this._findNearestEnemyInArc(baseAngle, /*range*/ 480, /*arcDeg*/ 60);
  if (!target) { this._drawZapBolt(px, py, px + Math.cos(baseAngle)*240, py + Math.sin(baseAngle)*240, 0.5); return; }
  target.hp -= 3 + stacks;
  this._drawZapBolt(px, py, target.x, target.y, 1);
  if (target.hp <= 0) this._killEnemy(target);
  this._chainLightning(target, 3 + stacks, (3 + stacks) * 0.7);  // recurse
}

