this.cameras.main.shake(80, 0.005);  // duration ms, intensity 0..1
// big hit:
this.cameras.main.shake(200, 0.015);

this.cameras.main.flash(80, 255, 0, 0, false);  // duration, r, g, b, force
// white screen-clear bomb:
this.cameras.main.flash(180, 255, 255, 255, false);

// Per-object bloom (Phaser 3.60+):
bullet.postFX.addBloom(0xffffff, 1, 1, 1.2, 1.5, 4);
// Outer glow on a pickup:
pickup.postFX.addGlow(0x00ffff, 8, 0, false, 0.1, 16);

function hitStop(scene, ms = 80) {
  const tw = scene.tweens.timeScale;
  scene.physics.world.timeScale = 0.05;  // physics slowdown is INVERTED in Phaser (high=slow)
  scene.tweens.timeScale = 0.05;
  scene.time.delayedCall(ms, () => {
    scene.physics.world.timeScale = 1;
    scene.tweens.timeScale = tw;
  });
}
hitStop(this, 80);

function popup(scene, x, y, text, color = '#ffffff') {
  const t = scene.add.text(x, y, text, {
    fontFamily: 'Arial Black', fontSize: '20px',
    color, stroke: '#000', strokeThickness: 4
  }).setOrigin(0.5).setDepth(1000);
  scene.tweens.add({
    targets: t, y: y - 40, alpha: 0,
    duration: 600, ease: 'Cubic.easeOut',
    onComplete: () => t.destroy()
  });
}
popup(this, enemy.x, enemy.y, '+100');

// Phaser 3.60+ particle API
this.add.particles(x, y, 'spark', {
  speed: { min: 80, max: 240 },
  angle: { min: 0, max: 360 },
  scale: { start: 0.6, end: 0 },
  lifespan: 400,
  quantity: 12,
  blendMode: 'ADD'
}).explode(12);

function hitFlash(sprite, scene, ms = 50) {
  sprite.setTintFill(0xffffff);
  scene.time.delayedCall(ms, () => sprite.clearTint());
}
hitFlash(enemy, this);

const c1 = Phaser.Display.Color.IntegerToColor(0x002288);
const c2 = Phaser.Display.Color.IntegerToColor(0x880033);
this.tweens.addCounter({
  from: 0, to: 1, duration: 2000, yoyo: true, repeat: -1,
  onUpdate: tw => {
    const c = Phaser.Display.Color.Interpolate.ColorWithColor(c1, c2, 1, tw.getValue());
    this.cameras.main.setBackgroundColor(
      Phaser.Display.Color.GetColor(c.r, c.g, c.b)
    );
  }
});

// Bomb / wave-clear punch
this.cameras.main.zoomTo(0.92, 80, 'Cubic.easeOut');
this.time.delayedCall(120, () => {
  this.cameras.main.zoomTo(1.0, 200, 'Back.easeOut');
});

this.tweens.chain({
  targets: player,
  tweens: [
    { scaleX: 1.2, scaleY: 0.8, duration: 60 },   // squash (anticipation)
    { scaleX: 0.85, scaleY: 1.2, duration: 120 }, // stretch (in air)
    { scaleX: 1.0, scaleY: 1.0, duration: 150, ease: 'Back.out(2)' }
  ]
});

function playerDeath(scene) {
  scene.physics.world.timeScale = 0.2;
  scene.tweens.timeScale = 0.4;
  scene.cameras.main.zoomTo(1.5, 800, 'Cubic.easeIn');
  scene.cameras.main.shake(800, 0.01);
  scene.time.delayedCall(1200, () => {
    scene.physics.world.timeScale = 1;
    scene.tweens.timeScale = 1;
    scene.scene.restart();
  });
}

// combo is current streak count
const rate = Math.min(1.0 + combo * 0.05, 2.0);
const detune = Math.min(combo * 30, 1200);
this.sound.play('tick', { rate, detune });

// Pre-create stems muted
const drums = this.sound.add('drums', { loop: true, volume: 0 });
const lead  = this.sound.add('lead',  { loop: true, volume: 0 });
drums.play(); lead.play();
// On combat enter:
this.tweens.add({ targets: drums, volume: 0.7, duration: 800 });
// On combat exit:
this.tweens.add({ targets: drums, volume: 0,   duration: 1200 });

function telegraph(scene, x, y, w, h, ms, onImpact) {
  const tel = scene.add.rectangle(x, y, w, h, 0xff2244, 0.25).setStrokeStyle(2, 0xff2244, 0.9);
  scene.tweens.add({
    targets: tel, alpha: { from: 0.25, to: 0.65 },
    yoyo: true, repeat: Math.floor(ms / 240),
    duration: 120,
    onComplete: () => { tel.destroy(); onImpact(); }
  });
}

// In create():
